#include <stdio.h>
#include <string.h>
#include <inttypes.h>

int main(){
    long long T,Q,D;
    if(scanf("%lld %lld %lld",&T,&Q,&D)!=3) return 0;
    for(long long tc=0; tc<T; ++tc){
        long long lx = -2000000000000000000LL, rx = 2000000000000000000LL;
        long long ly = -2000000000000000000LL, ry = 2000000000000000000LL;
        for(long long step=0; step<Q; ++step){
            long long mx = (lx+rx)/2;
            long long my = (ly+ry)/2;
            printf("1 %lld %lld\n", mx, my);
            fflush(stdout);
            char buf[16];
            if(scanf("%15s", buf)!=1) return 0;
            if(strcmp(buf,"O")==0) break;
            // shrink rectangle according to feedback
            if(strcmp(buf,"PY")==0){ lx = mx+1; }
            else if(strcmp(buf,"NY")==0){ rx = mx-1; }
            else if(strcmp(buf,"XP")==0){ ly = my+1; }
            else if(strcmp(buf,"XN")==0){ ry = my-1; }
            else if(strcmp(buf,"PP")==0){ lx = mx+1; ly = my+1; }
            else if(strcmp(buf,"PN")==0){ lx = mx+1; ry = my-1; }
            else if(strcmp(buf,"NP")==0){ rx = mx-1; ly = my+1; }
            else if(strcmp(buf,"NN")==0){ rx = mx-1; ry = my-1; }
            // enlarge by D to account for possible move
            if(D==1){
                lx -= 1; rx += 1; ly -= 1; ry += 1;
                if(lx < -2000000000000000000LL) lx = -2000000000000000000LL;
                if(rx > 2000000000000000000LL) rx = 2000000000000000000LL;
                if(ly < -2000000000000000000LL) ly = -2000000000000000000LL;
                if(ry > 2000000000000000000LL) ry = 2000000000000000000LL;
            }
        }
    }
    return 0;
}

