import java.io.*;
import java.util.*;

public class Main {
    static final long MIN = -2000000000000000000L;
    static final long MAX = 2000000000000000000L;
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        int Q = Integer.parseInt(st.nextToken());
        int D = Integer.parseInt(st.nextToken());
        PrintWriter out = new PrintWriter(new BufferedWriter(new OutputStreamWriter(System.out)));
        for (int tc = 0; tc < T; ++tc) {
            long lx = MIN, rx = MAX, ly = MIN, ry = MAX;
            for (int step = 0; step < Q; ++step) {
                long mx = (lx + rx) / 2;
                long my = (ly + ry) / 2;
                out.println("1 " + mx + " " + my);
                out.flush();
                String resp = br.readLine();
                if (resp.equals("O")) break;
                switch (resp) {
                    case "PY": lx = mx + 1; break;
                    case "NY": rx = mx - 1; break;
                    case "XP": ly = my + 1; break;
                    case "XN": ry = my - 1; break;
                    case "PP": lx = mx + 1; ly = my + 1; break;
                    case "PN": lx = mx + 1; ry = my - 1; break;
                    case "NP": rx = mx - 1; ly = my + 1; break;
                    case "NN": rx = mx - 1; ry = my - 1; break;
                }
                if (D == 1) {
                    lx = Math.max(lx - 1, MIN);
                    rx = Math.min(rx + 1, MAX);
                    ly = Math.max(ly - 1, MIN);
                    ry = Math.min(ry + 1, MAX);
                }
            }
        }
        out.flush();
    }
}

